import{_ as t,o,c as a,a2 as s}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"Project rules","description":"","frontmatter":{},"headers":[],"relativePath":"guide/project-rules.md","filePath":"guide/project-rules.md","lastUpdated":1782023771000}'),r={name:"guide/project-rules.md"};function i(n,e,c,l,d,u){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="project-rules" tabindex="-1">Project rules <a class="header-anchor" href="#project-rules" aria-label="Permalink to &quot;Project rules&quot;">​</a></h1><p>These rules apply to every contributor — human or agent. They are intentionally short and enforced by CI where possible. The canonical copy for automated contributors lives in <a href="https://github.com/Flopsstuff/korovany/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a>.</p><h2 id="_1-stack-language" tabindex="-1">1. Stack &amp; language <a class="header-anchor" href="#_1-stack-language" aria-label="Permalink to &quot;1. Stack &amp; language&quot;">​</a></h2><ul><li><strong>TypeScript, <code>strict</code> mode.</strong> No <code>any</code>; model real types. No <code>// @ts-ignore</code> without a one-line justification.</li><li><strong>React</strong> function components and hooks only — no class components.</li><li><strong>Babylon.js</strong> for all 3D/rendering; <strong>Redux Toolkit</strong> for shared state (slices under <code>src/store/</code>, typed <code>useAppSelector</code> / <code>useAppDispatch</code>).</li></ul><h2 id="_2-house-style" tabindex="-1">2. House style <a class="header-anchor" href="#_2-house-style" aria-label="Permalink to &quot;2. House style&quot;">​</a></h2><ul><li>2-space indent, single quotes, no semicolons (match the existing files).</li><li>Prefer named exports. Co-locate a unit by feature folder (see <a href="/korovany/guide/architecture">Architecture</a>).</li></ul><h2 id="_3-branches-commits-main" tabindex="-1">3. Branches, commits &amp; main <a class="header-anchor" href="#_3-branches-commits-main" aria-label="Permalink to &quot;3. Branches, commits &amp; main&quot;">​</a></h2><ul><li>Branch per issue: <code>flo-&lt;issue&gt;-&lt;slug&gt;</code> (e.g. <code>flo-253-project-conventions</code>).</li><li><code>main</code> is always green and deployable — never push work that fails CI.</li><li>Commit messages: imperative subject, reference the issue (<code>FLO-253</code>).</li><li><strong>Isolate your checkout — never work directly in the shared main checkout.</strong> Multiple agent runs share <code>/home/flop/projects/korovany</code>. Two runs staging/committing there at once race the git index and can lose or cross-contaminate work. Do your work in your own <code>git worktree add ../korovany-&lt;slug&gt; origin/main</code> (symlink <code>node_modules</code>), then commit and push from there. See <a href="/korovany/decisions/0003-concurrent-run-checkout-isolation">ADR 0003</a>.</li></ul><h2 id="_4-testing-is-mandatory" tabindex="-1">4. Testing is mandatory <a class="header-anchor" href="#_4-testing-is-mandatory" aria-label="Permalink to &quot;4. Testing is mandatory&quot;">​</a></h2><ul><li>Every feature or bugfix ships with tests in the same change.</li><li>Tests run on <strong>Vitest</strong>; co-locate as <code>*.test.ts</code> / <code>*.test.tsx</code> next to the code. CI runs <code>npm test</code> and must be green before merge.</li><li>Babylon scenes needing WebGL are stubbed in tests (jsdom has no GPU).</li></ul><h2 id="_5-documentation-is-mandatory-and-lives-with-the-code" tabindex="-1">5. Documentation is mandatory and lives with the code <a class="header-anchor" href="#_5-documentation-is-mandatory-and-lives-with-the-code" aria-label="Permalink to &quot;5. Documentation is mandatory and lives with the code&quot;">​</a></h2><ul><li>Docs live in <code>docs/</code> (this VitePress site) and are updated <strong>in the same change</strong> as the code — never deferred.</li><li><code>docs/</code> is published to <strong>GitHub Pages</strong> automatically on every push to <code>main</code>.</li></ul><h2 id="_6-binary-assets-via-git-lfs" tabindex="-1">6. Binary assets via Git LFS <a class="header-anchor" href="#_6-binary-assets-via-git-lfs" aria-label="Permalink to &quot;6. Binary assets via Git LFS&quot;">​</a></h2><ul><li>All binary assets (models, textures, audio, video) are tracked with <strong>Git LFS</strong> — see <code>.gitattributes</code>. Run <code>git lfs install</code> once per machine.</li><li>Source/raw assets go in <code>/assets</code>; assets imported by the bundler go in <code>src/assets/</code>.</li></ul><h2 id="_7-secrets" tabindex="-1">7. Secrets <a class="header-anchor" href="#_7-secrets" aria-label="Permalink to &quot;7. Secrets&quot;">​</a></h2><ul><li>Never commit secrets. Deploy credentials live in <strong>GitHub Actions secrets</strong> (see <a href="/korovany/operations/cloudflare-deploy">Cloudflare credentials</a>).</li></ul><h2 id="_8-automated-contributors" tabindex="-1">8. Automated contributors <a class="header-anchor" href="#_8-automated-contributors" aria-label="Permalink to &quot;8. Automated contributors&quot;">​</a></h2><ul><li><code>AGENTS.md</code> and <code>CLAUDE.md</code> at the repo root are authoritative for agents and must be kept in sync with these rules.</li></ul>',18)])])}const g=t(r,[["render",i]]);export{m as __pageData,g as default};
